import '@testing-library/jest-dom';
// This file was generated by an AI agent. Do not edit directly.
import * as React from 'react';
import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { ExpandableContent, type ExpandableContentProps } from './ExpandableContent';

const defaultText = 'Curabitur vitae nisl vitae nibh elementum tincidunt.';

const renderExpandableContent = (
  props?: Partial<ExpandableContentProps> & { children?: React.ReactNode }
) => {
  render(
    <ExpandableContent {...props}>
      {props?.children ?? defaultText.repeat(3)}
    </ExpandableContent>
  );

  const getControl = () =>
    screen.getByRole('button', { name: 'Toggle expanded content' });

  const getContent = () => {
    const control = getControl();
    const controlsId = control.getAttribute('aria-controls');
    if (!controlsId) {
      throw new Error('IconButton aria-controls attribute was not set.');
    }
    const element = document.getElementById(controlsId);
    if (!element) {
      throw new Error('Expandable content region was not found.');
    }
    return element;
  };

  return { getControl, getContent };
};

describe('ExpandableContent', () => {
  it('renders content slot', () => {
    renderExpandableContent();
    expect(screen.getByText(defaultText, { exact: false })).toBeInTheDocument();
  });

  it('renders control button', () => {
    renderExpandableContent();
    expect(screen.getByRole('button', { name: 'Toggle expanded content' })).toBeInTheDocument();
  });

  describe('uncontrolled toggle', () => {
    it('sets aria-expanded to true after click', async () => {
      const { getControl } = renderExpandableContent();
      const control = getControl();
      const user = userEvent.setup();
      await user.click(control);
      expect(control).toHaveAttribute('aria-expanded', 'true');
    });

    it('updates content data-state to open after click', async () => {
      const { getControl, getContent } = renderExpandableContent();
      const control = getControl();
      const user = userEvent.setup();
      await user.click(control);
      const content = getContent();
      expect(content.getAttribute('data-state')).toBe('open');
    });
  });

  describe('controlled mode', () => {
    it('calls onExpandedChange with next state', async () => {
      const handleExpandedChange = jest.fn();
      const { getControl } = renderExpandableContent({ expanded: false, onExpandedChange: handleExpandedChange });
      const control = getControl();
      const user = userEvent.setup();
      await user.click(control);
      expect(handleExpandedChange).toHaveBeenCalledWith(true);
    });

    it('does not change aria-expanded without external state update', async () => {
      const { getControl } = renderExpandableContent({ expanded: false, onExpandedChange: () => {} });
      const control = getControl();
      const user = userEvent.setup();
      await user.click(control);
      expect(control).toHaveAttribute('aria-expanded', 'false');
    });
  });

  it('links aria-controls to the content region id', () => {
    const { getControl, getContent } = renderExpandableContent();
    const control = getControl();
    const content = getContent();
    expect(control.getAttribute('aria-controls')).toBe(content.id);
  });

  describe('class assertions', () => {
    it('applies closed-state clamping classes when collapsed', () => {
      const { getContent } = renderExpandableContent();
      const content = getContent();
      expect(content).toHaveClass('data-[state=closed]:mh-75');
    });

    it('applies line clamp class when collapsed', () => {
      const { getContent } = renderExpandableContent();
      const content = getContent();
      expect(content).toHaveClass('data-[state=closed]:line-clamp-3');
    });

    it('applies rotate-0 class to control in closed state', () => {
      const { getControl } = renderExpandableContent();
      const control = getControl();
      expect(control).toHaveClass('peer-data-[state=closed]:rotate-0');
    });

    it('omits closed-state classes when expanded', () => {
      const { getContent } = renderExpandableContent({ defaultExpanded: true });
      const content = getContent();
      expect(content).not.toHaveClass('data-[state=closed]:mh-75');
    });

    it('omits line clamp class when expanded', () => {
      const { getContent } = renderExpandableContent({ defaultExpanded: true });
      const content = getContent();
      expect(content).not.toHaveClass('data-[state=closed]:line-clamp-3');
    });

    it('applies rotate-180 class to control when expanded', () => {
      const { getControl } = renderExpandableContent({ defaultExpanded: true });
      const control = getControl();
      expect(control).toHaveClass('peer-data-[state=open]:rotate-180');
    });
  });

  it('renders content before control in the DOM', () => {
    const { getContent } = renderExpandableContent();
    const root = screen.getByRole('button', { name: 'Toggle expanded content' }).parentElement;
    if (!root) {
      throw new Error('ExpandableContent root wrapper not found.');
    }
    const content = getContent();
    expect(root.firstElementChild === content).toBe(true);
  });
});
